                new GetActivenessRewardRequest { RewardType = 2 });
            GetActivenessRewardResponse weeklyResponse = (GetActivenessRewardResponse)ReadResponsePayload(
                harness,
                weeklyPacketId,
                nameof(GetActivenessRewardResponse),
                "GetActivenessRewardRequest weekly response",
                typeof(GetActivenessRewardResponse),
                maxPacketsToRead: 32);
            AssertEqual(0, weeklyResponse.Code, "GetActivenessRewardResponse weekly Code");
            AssertEqual(4, weeklyResponse.RewardGoodsList.Count, "GetActivenessRewardResponse weekly reward count");
            AssertEqual(3L, player.PlayerData.WeeklyActivenessRewardStatus, "GetActivenessRewardRequest weekly status");

            const int duplicatePacketId = 13_206;
            InvokeRegisteredRequestHandler(
                "GetActivenessRewardRequest",
                harness.Session,
                duplicatePacketId,
                new GetActivenessRewardRequest { RewardType = 1 });
            GetActivenessRewardResponse duplicateResponse = (GetActivenessRewardResponse)ReadResponsePayload(
                harness,
                duplicatePacketId,
                nameof(GetActivenessRewardResponse),
                "GetActivenessRewardRequest duplicate response",
                typeof(GetActivenessRewardResponse),
                maxPacketsToRead: 8);
            AssertEqual(20026012, duplicateResponse.Code, "GetActivenessRewardResponse duplicate Code");
            AssertEqual(0, duplicateResponse.RewardGoodsList.Count, "GetActivenessRewardResponse duplicate reward count");
        }

        private static void ValidateAchievementRewardCompatibility()
        {
            using MongoCollectionOverride mongoOverride = MongoCollectionOverride.InstallForShopCompatibility();
            const long playerId = 88_044;
            long day = DateTimeOffset.UtcNow.ToUnixTimeSeconds() / 86_400;
            AscNet.Common.Database.Player player = CreateDrawCompatibilityPlayer(playerId);
            player.PlayerData.Level = 10;
            player.MissionProgress = new AscNet.Common.Database.MissionProgressState
            {
                DailyResetDay = day,
                WeeklyResetWeek = (day + 3) / 7
            };
            using LoopbackSessionHarness harness = new(
                CreateDrawCompatibilityCharacter(playerId),
                player,
                CreateDrawCompatibilityInventory(playerId, []),
                "achievement-reward-compat-test");
            harness.Session.stage = new AscNet.Common.Database.Stage
            {
                Uid = playerId,
                Stages = new(),
                Course = new(),
                FinishedTasks = new()
            };

            const int claimPacketId = 13_207;
            InvokeRegisteredRequestHandler(
                "FinishTaskRequest",
                harness.Session,
                claimPacketId,
                new FinishTaskRequest { TaskId = 3660 });
            FinishTaskResponse claimResponse = (FinishTaskResponse)ReadResponsePayload(
                harness,
                claimPacketId,
                nameof(FinishTaskResponse),
                "Achievement FinishTaskRequest response",
                typeof(FinishTaskResponse),
                maxPacketsToRead: 32);
            AssertEqual(0, claimResponse.Code, "Achievement FinishTaskResponse Code");
            if (claimResponse.RewardGoodsList.Count == 0)
                throw new InvalidDataException("Achievement FinishTaskResponse omitted configured rewards.");
            AssertEqual(true, player.MissionProgress.ClaimedTaskIds.Contains(3660), "Achievement claim persistence");
            LoginTask claimedTask = RequiredStoryLoginTask(BuildTaskData(harness.Session), 3660);
            AssertEqual(4, claimedTask.State, "Achievement claimed task state");

            const int duplicatePacketId = 13_208;
            InvokeRegisteredRequestHandler(
                "FinishTaskRequest",
                harness.Session,
                duplicatePacketId,
                new FinishTaskRequest { TaskId = 3660 });
            FinishTaskResponse duplicateResponse = (FinishTaskResponse)ReadResponsePayload(
                harness,
                duplicatePacketId,
                nameof(FinishTaskResponse),
                "Achievement duplicate FinishTaskRequest response",
                typeof(FinishTaskResponse),
                maxPacketsToRead: 8);
            AssertEqual(20026006, duplicateResponse.Code, "Achievement duplicate FinishTaskResponse Code");
            AssertEqual(0, duplicateResponse.RewardGoodsList.Count, "Achievement duplicate reward count");
        }


        private static void ValidateLoginStartupPushOrder()
        {
            using MongoCollectionOverride mongoOverride = MongoCollectionOverride.InstallForShopCompatibility();
            Type accountModule = RequiredAscNetGameServerType("AscNet.GameServer.Handlers.AccountModule");
            MethodInfo doLogin = RequiredMethod(
                accountModule,
                "DoLogin",
                BindingFlags.Static | BindingFlags.NonPublic,
                [typeof(Session)]);

            const long playerId = 88_003;
            const long defaultChatBoardId = 25_000_001;
            const long existingCurrentChatBoardId = 25_000_007;
            AscNet.Common.Database.Player player = CreateDrawCompatibilityPlayer(playerId);
            player.PlayerData.LastLoginTime = DateTimeOffset.UtcNow.AddDays(-1).ToUnixTimeSeconds();
            AscNet.Common.Database.Character character = CreateDrawCompatibilityCharacter(playerId);
            character.Characters.Add(CreateLoginAccountCompatibilityCharacter(1021001, fashionId: 3021001));

            const int validStartupItemId = AscNet.Common.Database.Inventory.Coin;
            const int invalidStartupItemId = 0;
            const long validStartupItemCount = 12_345;
            AscNet.Common.Database.Inventory inventory = CreateDrawCompatibilityInventory(
                playerId,
                [
                    new Item { Id = validStartupItemId, Count = validStartupItemCount },
                    new Item { Id = invalidStartupItemId, Count = 9_999 }
                ]);
            using LoopbackSessionHarness harness = new(
                character,
                player,
                inventory,
                "login-account-push-order-compat-test");
            harness.Session.stage = CreateLoginAccountCompatibilityStage(playerId);

            doLogin.Invoke(null, [harness.Session]);

            string[] retailCriticalStartupOrderThroughPassport =
            [
                nameof(NotifyLogin),
                nameof(NotifyPayInfo),
                nameof(NotifyMails),
                nameof(NotifyEquipChipGroupList),
                nameof(NotifyEquipChipAutoRecycleSite),
                nameof(NotifyEquipGuideData),
                nameof(NotifyArchiveLoginData),
                "NotifyLoginAwarenessInfo",
                nameof(NotifyChatLoginData),
                nameof(NotifySocialData),
                nameof(NotifyTaskData),
                nameof(NotifyActivenessStatus),
                nameof(NotifyNewPlayerTaskStatus),
                nameof(PurchaseDailyNotify),
                nameof(NotifyPurchaseRecommendConfig),
                "NotifyReviewConfig",
                "NotifyPassportData",
                "NotifyMentorData",
                "NotifyMentorChat",
                "NotifyGuildData",
                nameof(NotifyMails),
                "NotifyWheelchairManualActivityUpdate"
            ];
            string[] purchaseRelatedPushes =
            [
                nameof(PurchaseDailyNotify),
                nameof(NotifyPurchaseRecommendConfig)
            ];

            List<string> startupPushes = [];
            List<Packet.Push> startupPushPackets = [];
            Dictionary<string, Packet.Push> startupPushesByName = new(StringComparer.Ordinal);
            const int maxStartupPushesUntilRetailTail = 192;
            for (int packetIndex = 0;
                packetIndex < maxStartupPushesUntilRetailTail && !startupPushes.Contains("NotifyWheelchairManualActivityUpdate");
                packetIndex++)
            {
                Packet.Push startupPush = ReadStartupPush(harness, $"AccountModule.DoLogin startup push {packetIndex + 1}");
                startupPushes.Add(startupPush.Name);
                startupPushPackets.Add(startupPush);
                startupPushesByName.TryAdd(startupPush.Name, startupPush);
            }

            if (!startupPushes.Contains("NotifyWheelchairManualActivityUpdate"))
                throw new InvalidDataException($"AccountModule.DoLogin startup pushes: expected retail startup tail NotifyWheelchairManualActivityUpdate; observed {DescribePushes(startupPushes)}.");

            AssertPushSubsequence(
                startupPushes,
                retailCriticalStartupOrderThroughPassport,
                "AccountModule.DoLogin retail-critical startup order");
            int guildDormPlayerDataIndex = RequiredPushIndex(
                startupPushes,
                "NotifyGuildDormPlayerData",
                0,
                "AccountModule.DoLogin chat-board predecessor");
            int chatBoardLoginDataIndex = RequiredPushIndex(
                startupPushes,
                nameof(NotifyChatBoardLoginData),
                0,
                "AccountModule.DoLogin NotifyChatBoardLoginData startup push");
            if (chatBoardLoginDataIndex <= guildDormPlayerDataIndex)
                throw new InvalidDataException($"AccountModule.DoLogin startup pushes: expected {nameof(NotifyChatBoardLoginData)} after NotifyGuildDormPlayerData; observed {DescribePushes(startupPushes)}.");

            NotifyLogin startupLogin = DeserializeStartupPush<NotifyLogin>(
                startupPushesByName,
                nameof(NotifyLogin),
                "AccountModule.DoLogin NotifyLogin startup payload");
            AssertClientItemList(
                startupLogin.ItemList,
                validStartupItemId,
                validStartupItemCount,
                invalidStartupItemId,
                "AccountModule.DoLogin NotifyLogin.ItemList");
            AssertIntegerList(
                [101, 102, 103, 104, 1, 105, 2, 3, 111, 106, 4, 5, 107, 108, 6, 7, 8, 9, 109,
                    10, 11, 112, 12, 110, 14, 19, 25, 18, 20, 22, 24, 555, 21, 23, 599, 600,
                    3108, 4108, 557, 558, 601, 602, 603, 604, 605, 556, 606, 607, 608, 609],
                startupLogin.PlayerData.Communications,
                "AccountModule.DoLogin NotifyLogin.PlayerData.Communications retail defaults");
            AssertIntegerSetContainsAll(
                [801, 802, 803, 20000],
                startupLogin.PlayerData.Marks,
                "AccountModule.DoLogin NotifyLogin.PlayerData.Marks functional entrance gate defaults");
            AssertIntegerList(
                [8001],
                startupLogin.PlayerData.ShieldFuncList.Cast<object>().Select(value => Convert.ToInt64(value)).ToArray(),
                "AccountModule.DoLogin NotifyLogin.PlayerData.ShieldFuncList retail defaults");

            if (startupLogin.FubenMainLine2Data is FubenMainLine2Data startupMainLine2Data)
            {
                if (startupMainLine2Data.LastPassStage.ContainsKey(1041))
                    throw new InvalidDataException("AccountModule.DoLogin NotifyLogin.FubenMainLine2Data: current event startup must not seed Homeward/MainLine2 chapter 1041 LastPassStage.");
                if (startupMainLine2Data.MainDatas.Any(mainData => mainData.Id == 1041))
                    throw new InvalidDataException("AccountModule.DoLogin NotifyLogin.FubenMainLine2Data: current event startup must not seed Homeward/MainLine2 chapter 1041 MainDatas.");
                if (startupMainLine2Data.ChapterDatas.Any(chapterData => chapterData.Id == 1041))
                    throw new InvalidDataException("AccountModule.DoLogin NotifyLogin.FubenMainLine2Data: current event startup must not seed Homeward/MainLine2 chapter 1041 ChapterDatas.");
                if (startupMainLine2Data.LastExhibitionChapterId == 61)
                    throw new InvalidDataException("AccountModule.DoLogin NotifyLogin.FubenMainLine2Data: current event startup must not seed Homeward/MainLine2 exhibition chapter 61.");
            }

            FunctionOpenTimeConfig? startupFunctionOpenTime = startupLogin.FunctionOpenTimeConfigList?
                .SingleOrDefault(config => config.FunctionId == 20000 && config.TimeId == 100);
            if (startupFunctionOpenTime is null)
                throw new InvalidDataException("AccountModule.DoLogin NotifyLogin.FunctionOpenTimeConfigList: missing FunctionId 20000 / TimeId 100.");
            AssertRetroFestivalTimeLimitControlsPresent(
                startupLogin.TimeLimitCtrlConfigList,
                "AccountModule.DoLogin NotifyLogin.TimeLimitCtrlConfigList Retro/Festival display controls");

            NotifyArchiveLoginData startupArchiveLoginData = DeserializeStartupPush<NotifyArchiveLoginData>(
                startupPushesByName,
                nameof(NotifyArchiveLoginData),
                "AccountModule.DoLogin NotifyArchiveLoginData startup payload");
            AssertIntegerList(
                Enumerable.Range(1, 32).Select(id => (long)id).ToArray(),
                startupArchiveLoginData.UnlockComics.Select(id => (long)id).ToArray(),
                "AccountModule.DoLogin NotifyArchiveLoginData.UnlockComics captured retail defaults");
            NotifyFunctionalEntranceData startupFunctionalEntranceData = DeserializeStartupPush<NotifyFunctionalEntranceData>(
                startupPushesByName,
                nameof(NotifyFunctionalEntranceData),
                "AccountModule.DoLogin NotifyFunctionalEntranceData startup payload");
            AssertIntegerDictionary(
                new Dictionary<int, int> { [20000] = 45 },
                startupFunctionalEntranceData.RedPointDatas,
                "AccountModule.DoLogin NotifyFunctionalEntranceData.RedPointDatas functional entrance redpoint");

            AscNet.GameServer.Handlers.NotifyWorldChat startupWorldChat = DeserializeStartupPush<AscNet.GameServer.Handlers.NotifyWorldChat>(
                startupPushesByName,
                nameof(AscNet.GameServer.Handlers.NotifyWorldChat),
                "AccountModule.DoLogin NotifyWorldChat startup payload");
            AssertWorldChatSeed(startupWorldChat, "AccountModule.DoLogin NotifyWorldChat startup seed");

            JObject calendarPayload = DeserializeStartupPushMap(
                startupPushesByName,
                "NotifyNewActivityCalendarData",
                "AccountModule.DoLogin NotifyNewActivityCalendarData startup payload");
            AssertIntegerSetContainsAll(
                [45001, 45005, 45010],
                RequiredIntegerArray(calendarPayload, "OpenActivityIds", "AccountModule.DoLogin NotifyNewActivityCalendarData startup payload"),
                "AccountModule.DoLogin NotifyNewActivityCalendarData.OpenActivityIds current event ids");
            AssertEveryGotRewardsArrayEmpty(
                calendarPayload,
                "AccountModule.DoLogin NotifyNewActivityCalendarData startup payload");

            JObject manualPayload = DeserializeStartupPushMap(
                startupPushesByName,
                "NotifyWheelchairManualActivity",
                "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload");
            AssertEqual(1L, RequiredValue<long>(manualPayload, "ActivityId", JTokenType.Integer, "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload"), "AccountModule.DoLogin NotifyWheelchairManualActivity.ActivityId");
            AssertEqual(1007L, RequiredValue<long>(manualPayload, "PlanId", JTokenType.Integer, "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload"), "AccountModule.DoLogin NotifyWheelchairManualActivity.PlanId");
            AssertEqual(1L, RequiredValue<long>(manualPayload, "BpLevel", JTokenType.Integer, "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload"), "AccountModule.DoLogin NotifyWheelchairManualActivity.BpLevel fresh-account level");
            AssertEqual(false, RequiredValue<bool>(manualPayload, "IsSeniorManualUnlock", JTokenType.Boolean, "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload"), "AccountModule.DoLogin NotifyWheelchairManualActivity.IsSeniorManualUnlock fresh-account lock state");
            AssertEmptyJsonArray(manualPayload, "GetRewardManualRewardIds", "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload");
            AssertEmptyJsonArray(manualPayload, "GetRewardPlanIds", "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload");
            AssertEmptyJsonArray(manualPayload, "FinishStageIds", "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload");
            AssertEmptyJsonArray(manualPayload, "TimeLimitActivityInfos", "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload");
            AssertEmptyJsonArray(manualPayload, "WeekActivityInfos", "AccountModule.DoLogin NotifyWheelchairManualActivity startup payload");

            AssertStartupPayloadMapContainsKeys(
                startupPushesByName,
                "NotifyWheelchairManualActivityUpdate",
                "AccountModule.DoLogin NotifyWheelchairManualActivityUpdate startup payload",
                "UpdateTimeLimitActivityInfos",
                "UpdateWeekActivityInfos",
                "CurrentGuildBossEndTime");

            JObject accumulatedPayPayload = DeserializeStartupPushMap(
                startupPushesByName,
                nameof(NotifyAccumulatedPayData),
                "AccountModule.DoLogin NotifyAccumulatedPayData startup payload");
            AssertEqual(1L, RequiredValue<long>(accumulatedPayPayload, "PayId", JTokenType.Integer, "AccountModule.DoLogin NotifyAccumulatedPayData startup payload"), "AccountModule.DoLogin NotifyAccumulatedPayData.PayId");
            AssertEqual(0d, RequiredNumericValue(accumulatedPayPayload, "PayMoney", "AccountModule.DoLogin NotifyAccumulatedPayData startup payload"), "AccountModule.DoLogin NotifyAccumulatedPayData.PayMoney fresh-account total");
            AssertEmptyJsonArray(accumulatedPayPayload, "PayRewardIds", "AccountModule.DoLogin NotifyAccumulatedPayData startup payload");
            AssertEmptyJsonArray(accumulatedPayPayload, "ExtraPayRewardIds", "AccountModule.DoLogin NotifyAccumulatedPayData startup payload");

            JObject accumulateExpendPayload = DeserializeStartupPushMap(
                startupPushesByName,
                "NotifyAccumulateExpendData",
                "AccountModule.DoLogin NotifyAccumulateExpendData startup payload");
            AssertEqual(7L, RequiredValue<long>(accumulateExpendPayload, "ActivityId", JTokenType.Integer, "AccountModule.DoLogin NotifyAccumulateExpendData startup payload"), "AccountModule.DoLogin NotifyAccumulateExpendData.ActivityId");

            JObject festivalPayload = DeserializeStartupPushMap(
                startupPushesByName,
                nameof(NotifyFestivalData),
                "AccountModule.DoLogin NotifyFestivalData startup payload");
            JArray festivalInfos = (JArray)RequiredToken(festivalPayload, "FestivalInfos", JTokenType.Array, "AccountModule.DoLogin NotifyFestivalData startup payload");
            if (festivalInfos.Count == 0)
                throw new InvalidDataException("AccountModule.DoLogin NotifyFestivalData.FestivalInfos: expected current event festival entries.");
            AssertIntegerSetContainsAll(
                ExpectedRetroFestivalInfoIds,
                festivalInfos
                    .OfType<JObject>()
                    .Select(festivalInfo => festivalInfo.Value<long>("Id"))
                    .ToArray(),
                "AccountModule.DoLogin NotifyFestivalData.FestivalInfos Retro/Festival ids");

            JObject game2048Payload = DeserializeStartupPushMap(
                startupPushesByName,
                "NotifyGame2048DataDb",
                "AccountModule.DoLogin NotifyGame2048DataDb startup payload");
            JObject game2048Data = RequiredObject(game2048Payload, "Game2048DataDb", "AccountModule.DoLogin NotifyGame2048DataDb startup payload");
            AssertEqual(4L, RequiredValue<long>(game2048Data, "ActivityId", JTokenType.Integer, "AccountModule.DoLogin NotifyGame2048DataDb.Game2048DataDb startup payload"), "AccountModule.DoLogin NotifyGame2048DataDb.Game2048DataDb.ActivityId");

            JObject collectionPayload = DeserializeStartupPushMap(
                startupPushesByName,
                "NotifyGameCollectionData",
                "AccountModule.DoLogin NotifyGameCollectionData startup payload");
            JObject collectionData = RequiredObject(collectionPayload, "GameCollectionData", "AccountModule.DoLogin NotifyGameCollectionData startup payload");
            AssertEqual(1L, RequiredValue<long>(collectionData, "ActivityId", JTokenType.Integer, "AccountModule.DoLogin NotifyGameCollectionData.GameCollectionData startup payload"), "AccountModule.DoLogin NotifyGameCollectionData.GameCollectionData.ActivityId");

            JObject minerPayload = DeserializeStartupPushMap(
                startupPushesByName,
                "NotifyGoldenMinerGameInfo",
                "AccountModule.DoLogin NotifyGoldenMinerGameInfo startup payload");
            JObject minerStageData = RequiredObject(minerPayload, "StageDataDb", "AccountModule.DoLogin NotifyGoldenMinerGameInfo startup payload");
            AssertEqual(7L, RequiredValue<long>(minerStageData, "ActivityId", JTokenType.Integer, "AccountModule.DoLogin NotifyGoldenMinerGameInfo.StageDataDb startup payload"), "AccountModule.DoLogin NotifyGoldenMinerGameInfo.StageDataDb.ActivityId");
            AssertEqual(0L, RequiredValue<long>(minerStageData, "StageScores", JTokenType.Integer, "AccountModule.DoLogin NotifyGoldenMinerGameInfo.StageDataDb startup payload"), "AccountModule.DoLogin NotifyGoldenMinerGameInfo.StageDataDb.StageScores fresh-account score");
            AssertEqual(0L, RequiredValue<long>(minerStageData, "TotalPlayCount", JTokenType.Integer, "AccountModule.DoLogin NotifyGoldenMinerGameInfo.StageDataDb startup payload"), "AccountModule.DoLogin NotifyGoldenMinerGameInfo.StageDataDb.TotalPlayCount fresh-account play count");
            AssertEmptyJsonArray(minerStageData, "CharacterDbs", "AccountModule.DoLogin NotifyGoldenMinerGameInfo.StageDataDb startup payload");
            AssertEmptyJsonArray(minerStageData, "FinishStageId", "AccountModule.DoLogin NotifyGoldenMinerGameInfo.StageDataDb startup payload");

            JObject turntablePayload = DeserializeStartupPushMap(
                startupPushesByName,
                "NotifyTurntableData",
                "AccountModule.DoLogin NotifyTurntableData startup payload");
            JObject turntableData = RequiredObject(turntablePayload, "TurntableData", "AccountModule.DoLogin NotifyTurntableData startup payload");
            AssertEqual(4L, RequiredValue<long>(turntableData, "ActivityId", JTokenType.Integer, "AccountModule.DoLogin NotifyTurntableData.TurntableData startup payload"), "AccountModule.DoLogin NotifyTurntableData.TurntableData.ActivityId");
            AssertEqual(0L, RequiredValue<long>(turntableData, "AccumulateDrawNum", JTokenType.Integer, "AccountModule.DoLogin NotifyTurntableData.TurntableData startup payload"), "AccountModule.DoLogin NotifyTurntableData.TurntableData.AccumulateDrawNum fresh-account spins");
            AssertEmptyJsonArray(turntableData, "GainRewardInfos", "AccountModule.DoLogin NotifyTurntableData.TurntableData startup payload");
            AssertEmptyJsonArray(turntableData, "GainRecords", "AccountModule.DoLogin NotifyTurntableData.TurntableData startup payload");
            AssertEmptyJsonArray(turntableData, "GainAccumulateRewardIndexs", "AccountModule.DoLogin NotifyTurntableData.TurntableData startup payload");

            Dictionary<long, JObject> startupTasksById = DeserializeStartupTasksById(
                startupPushPackets,
                "AccountModule.DoLogin startup NotifyTask packets");
            foreach (long requiredRetroArcadeTaskId in new long[] { 78020, 86513, 85951, 990000, 990050, 990101 })
            {
                AssertStartupTasksContainFreshTask(
                    startupTasksById,
                    requiredRetroArcadeTaskId,
                    "AccountModule.DoLogin startup Retro Arcade NotifyTask gate batches");
            }
            AssertStartupPayloadMapContainsKeys(
                startupPushesByName,
                nameof(NotifyChatBoardLoginData),
                "AccountModule.DoLogin NotifyChatBoardLoginData startup payload",
                nameof(NotifyChatBoardLoginData.CurrentChatBoardId),
                nameof(NotifyChatBoardLoginData.ChatBoards));
            NotifyChatBoardLoginData startupChatBoardLoginData = DeserializeStartupPush<NotifyChatBoardLoginData>(
                startupPushesByName,
                nameof(NotifyChatBoardLoginData),
                "AccountModule.DoLogin NotifyChatBoardLoginData startup payload");
            AssertChatBoardLoginData(
                startupChatBoardLoginData,
                defaultChatBoardId,
                defaultChatBoardId,
                "AccountModule.DoLogin sparse-player NotifyChatBoardLoginData startup payload");
            AssertEqual(defaultChatBoardId, player.PlayerData.CurrentChatBoardId, "AccountModule.DoLogin sparse-player CurrentChatBoardId default persistence");

            AssertStartupPayloadMapContainsKeys(
                startupPushesByName,
                "NotifyLoginAwarenessInfo",
                "AccountModule.DoLogin NotifyLoginAwarenessInfo startup payload",
                "AwarenessInfo");
            AssertStartupPayloadMapContainsKeys(
                startupPushesByName,
                "NotifyExperimentData",
                "AccountModule.DoLogin NotifyExperimentData startup payload",
                "FinishIds",
                "ExperimentInfos");
            AssertStartupPayloadMapContainsKeys(
                startupPushesByName,
                nameof(NotifyFubenBossSingleData),
                "AccountModule.DoLogin NotifyFubenBossSingleData startup payload",
                "FubenBossSingleData",
                "BossListDict");
            AssertStartupPayloadMapContainsKeys(
                startupPushesByName,
                "NotifyPassportData",
                "AccountModule.DoLogin NotifyPassportData startup payload",
                "ActivityId",
                "Level",
                "BaseInfo",
                "PassportInfos",
                "LastTimeBaseInfo",
                "IsGetSupplyReward",
                "IsActivateRegressionTask",
                "IsActivateNewbieTask");

            AssertForbiddenStartupPushesAbsent(
                startupPushes,
                [nameof(NotifyItemDataList), nameof(NotifyStageData), nameof(NotifyCharacterDataList), "NotifyPassportBaseInfo", "NotifyPassportAutoGetTaskReward", "NotifyGuildWarActivityData", "NotifyClientShieldFunction", "NotifyClientFunctionOpenConfig"],
                "AccountModule.DoLogin retail startup pushes");

            int purchasePredecessorIndex = RequiredPushIndex(startupPushes, nameof(NotifyNewPlayerTaskStatus), 0, "AccountModule.DoLogin purchase predecessor");
            foreach (string purchaseRelatedPush in purchaseRelatedPushes)
            {
                int purchaseRelatedPushIndex = RequiredPushIndex(startupPushes, purchaseRelatedPush, 0, "AccountModule.DoLogin purchase-related push");
                if (purchaseRelatedPushIndex <= purchasePredecessorIndex)
                    throw new InvalidDataException($"AccountModule.DoLogin startup pushes: expected {purchaseRelatedPush} only after {nameof(NotifyNewPlayerTaskStatus)}; observed {DescribePushes(startupPushes)}.");
            }

            List<string> remainingSynchronousPushes = DrainAvailablePushNames(
                harness,
                "AccountModule.DoLogin remaining synchronous startup packet");
            if (remainingSynchronousPushes.Count > 0)
                throw new InvalidDataException($"AccountModule.DoLogin startup pushes: expected no synchronous post-startup packets after NotifyWheelchairManualActivityUpdate; observed {DescribePushes(remainingSynchronousPushes)}.");

            Thread.Sleep(1_000);
            List<string> latePushes = DrainAvailablePushNames(
                harness,
                "AccountModule.DoLogin delayed post-startup packet");
            if (latePushes.Count > 0)
                throw new InvalidDataException($"AccountModule.DoLogin startup pushes: expected no delayed post-login replay after synchronous startup completed; observed {DescribePushes(latePushes)}.");

            AscNet.Common.Database.Player existingChatBoardPlayer = CreateDrawCompatibilityPlayer(playerId + 1);
            existingChatBoardPlayer.PlayerData.CurrentChatBoardId = existingCurrentChatBoardId;
            existingChatBoardPlayer.PlayerData.LastLoginTime = DateTimeOffset.UtcNow.AddDays(-1).ToUnixTimeSeconds();
            AscNet.Common.Database.Character existingChatBoardCharacter = CreateDrawCompatibilityCharacter(playerId + 1);
            existingChatBoardCharacter.Characters.Add(CreateLoginAccountCompatibilityCharacter(1021001, fashionId: 3021001));
            using LoopbackSessionHarness existingChatBoardHarness = new(
                existingChatBoardCharacter,
                existingChatBoardPlayer,
                CreateDrawCompatibilityInventory(playerId + 1, []),
                "login-account-existing-chat-board-compat-test");
            existingChatBoardHarness.Session.stage = CreateLoginAccountCompatibilityStage(playerId + 1);

            doLogin.Invoke(null, [existingChatBoardHarness.Session]);
            Dictionary<string, Packet.Push> existingChatBoardStartupPushesByName = ReadStartupPushesByNameUntil(
                existingChatBoardHarness,
                nameof(NotifyChatBoardLoginData),
                maxStartupPushesUntilRetailTail,
                "AccountModule.DoLogin existing-chat-board startup pushes");
            NotifyChatBoardLoginData existingChatBoardLoginData = DeserializeStartupPush<NotifyChatBoardLoginData>(
                existingChatBoardStartupPushesByName,
                nameof(NotifyChatBoardLoginData),
                "AccountModule.DoLogin existing-chat-board NotifyChatBoardLoginData startup payload");
            AssertChatBoardLoginData(
                existingChatBoardLoginData,
                existingCurrentChatBoardId,
                defaultChatBoardId,
                "AccountModule.DoLogin existing CurrentChatBoardId NotifyChatBoardLoginData startup payload");
            AssertEqual(existingCurrentChatBoardId, existingChatBoardPlayer.PlayerData.CurrentChatBoardId, "AccountModule.DoLogin existing CurrentChatBoardId preservation");

            static List<string> DrainAvailablePushNames(LoopbackSessionHarness harness, string name)
            {
                List<string> pushNames = [];
                int packetIndex = 0;
                while (harness.TryReadAvailablePacket($"{name} {packetIndex + 1}", out Packet packet))
                {
                    AssertEqual(Packet.ContentType.Push, packet.Type, $"{name} {packetIndex + 1} packet type");
                    Packet.Push push = MessagePackSerializer.Deserialize<Packet.Push>(packet.Content);
                    pushNames.Add(push.Name);
                    packetIndex++;
                }

                return pushNames;
            }

            static void AssertPushSubsequence(IReadOnlyList<string> pushNames, IReadOnlyList<string> expectedOrder, string name)
            {
                int searchStart = 0;
                foreach (string expectedPushName in expectedOrder)
                {
                    int actualIndex = RequiredPushIndex(pushNames, expectedPushName, searchStart, name);
                    searchStart = actualIndex + 1;
                }
            }

            static int RequiredPushIndex(IReadOnlyList<string> pushNames, string expectedPushName, int searchStart, string name)
            {
                int index = FindPushIndex(pushNames, expectedPushName, searchStart);
                if (index < 0)
                    throw new InvalidDataException($"{name}: expected {expectedPushName} at or after startup push {searchStart + 1}; observed {DescribePushes(pushNames)}.");

                return index;
            }

            static int FindPushIndex(IReadOnlyList<string> pushNames, string expectedPushName, int searchStart)
            {
                for (int index = Math.Max(0, searchStart); index < pushNames.Count; index++)
                {
                    if (pushNames[index] == expectedPushName)
                        return index;
                }

                return -1;
            }

            static Dictionary<string, Packet.Push> ReadStartupPushesByNameUntil(
                LoopbackSessionHarness harness,
                string requiredPushName,
                int maxStartupPushes,
                string name)
            {
                List<string> pushNames = [];
                Dictionary<string, Packet.Push> pushesByName = new(StringComparer.Ordinal);
                for (int packetIndex = 0;
                    packetIndex < maxStartupPushes && !pushNames.Contains(requiredPushName);
                    packetIndex++)
                {
                    Packet.Push startupPush = ReadStartupPush(harness, $"{name} {packetIndex + 1}");
                    pushNames.Add(startupPush.Name);
                    pushesByName.TryAdd(startupPush.Name, startupPush);
                }

                if (!pushNames.Contains(requiredPushName))
                    throw new InvalidDataException($"{name}: expected {requiredPushName}; observed {DescribePushes(pushNames)}.");

                return pushesByName;
            }

            static Packet.Push ReadStartupPush(LoopbackSessionHarness harness, string name)
            {
                Packet packet = harness.ReadPacket(name);
                AssertEqual(Packet.ContentType.Push, packet.Type, $"{name} packet type");
                return MessagePackSerializer.Deserialize<Packet.Push>(packet.Content);
            }

            static TPayload DeserializeStartupPush<TPayload>(
                IReadOnlyDictionary<string, Packet.Push> startupPushesByName,
                string pushName,
                string name)
            {
                if (!startupPushesByName.TryGetValue(pushName, out Packet.Push? push))
                    throw new InvalidDataException($"{name}: expected {pushName} during login startup.");

                return MessagePackSerializer.Deserialize<TPayload>(push.Content);
            }

            static JObject DeserializeStartupPushMap(
                IReadOnlyDictionary<string, Packet.Push> startupPushesByName,
                string pushName,
                string name)
            {
                if (!startupPushesByName.TryGetValue(pushName, out Packet.Push? push))
                    throw new InvalidDataException($"{name}: expected {pushName} during login startup.");

                try
                {
                    return JObject.Parse(MessagePackSerializer.ConvertToJson(push.Content));
                }
                catch (Exception ex) when (ex is not InvalidDataException)
                {
                    throw new InvalidDataException($"{name}: expected a MessagePack map payload.", ex);
                }
            }

            static IReadOnlyList<long> RequiredIntegerArray(JObject payload, string memberName, string name)
            {
                JArray values = (JArray)RequiredToken(payload, memberName, JTokenType.Array, name);
                long[] integers = new long[values.Count];
                for (int index = 0; index < values.Count; index++)
                {
                    JToken value = values[index]!;
                    if (value.Type != JTokenType.Integer)
                        throw new InvalidDataException($"{name} {memberName}[{index}]: expected JSON Integer, got {value.Type}.");
                    integers[index] = value.Value<long>();
                }

                return integers;
            }

            static void AssertEmptyJsonArray(JObject payload, string memberName, string name)
            {
                JArray values = (JArray)RequiredToken(payload, memberName, JTokenType.Array, name);
                if (values.Count != 0)
                    throw new InvalidDataException($"{name} {memberName}: expected an empty array, got {values.Count} entries.");
            }

            static double RequiredNumericValue(JObject payload, string memberName, string name)
            {
                if (!payload.TryGetValue(memberName, out JToken? token))
                    throw new InvalidDataException($"{name}: missing JSON field '{memberName}'.");
                if (token.Type != JTokenType.Integer && token.Type != JTokenType.Float)
                    throw new InvalidDataException($"{name} {memberName}: expected JSON numeric value, got {token.Type}.");

                return token.Value<double>();
            }

            static void AssertEveryGotRewardsArrayEmpty(JToken payload, string name)
            {
                int gotRewardsArrayCount = 0;
                CountEmptyGotRewardsArrays(payload, name, ref gotRewardsArrayCount);
                if (gotRewardsArrayCount == 0)
                    throw new InvalidDataException($"{name}: expected at least one nested GotRewards array.");
            }

            static void CountEmptyGotRewardsArrays(JToken token, string name, ref int gotRewardsArrayCount)
            {
                if (token is JObject obj)
                {
                    foreach (JProperty property in obj.Properties())
                    {
                        if (property.Name == "GotRewards")
                        {
                            if (property.Value is not JArray gotRewards)
                                throw new InvalidDataException($"{name} {property.Path}: expected JSON Array, got {property.Value.Type}.");
                            gotRewardsArrayCount++;
                            if (gotRewards.Count != 0)
                                throw new InvalidDataException($"{name} {property.Path}: expected fresh-account GotRewards to be empty, got {gotRewards.Count} entries.");
                        }

                        CountEmptyGotRewardsArrays(property.Value, name, ref gotRewardsArrayCount);
                    }
                }
                else if (token is JArray array)
                {
                    foreach (JToken child in array)
                        CountEmptyGotRewardsArrays(child, name, ref gotRewardsArrayCount);
                }
            }

            static Dictionary<long, JObject> DeserializeStartupTasksById(
                IReadOnlyList<Packet.Push> startupPushPackets,
                string name)
            {
                Dictionary<long, JObject> tasksById = new();
                int notifyTaskPushCount = 0;
                for (int pushIndex = 0; pushIndex < startupPushPackets.Count; pushIndex++)
                {
                    Packet.Push push = startupPushPackets[pushIndex];
                    if (push.Name != nameof(NotifyTask))
                        continue;

                    notifyTaskPushCount++;
                    string pushName = $"{name} NotifyTask push {notifyTaskPushCount} at startup index {pushIndex + 1}";
                    JObject notifyTaskPayload = DeserializeStartupPushContentMap(push, pushName);
                    JObject tasksPayload = RequiredObject(notifyTaskPayload, "Tasks", pushName);
                    JArray tasks = (JArray)RequiredToken(tasksPayload, "Tasks", JTokenType.Array, pushName);
                    if (tasks.Count == 0)
                        throw new InvalidDataException($"{pushName} Tasks.Tasks: expected at least one task entry.");

                    for (int taskIndex = 0; taskIndex < tasks.Count; taskIndex++)
                    {
                        if (tasks[taskIndex] is not JObject taskPayload)
                            throw new InvalidDataException($"{pushName} Tasks.Tasks[{taskIndex}]: expected JSON Object, got {tasks[taskIndex]!.Type}.");

                        long taskId = RequiredValue<long>(taskPayload, "Id", JTokenType.Integer, $"{pushName} Tasks.Tasks[{taskIndex}]");
                        tasksById.TryAdd(taskId, taskPayload);
                    }
                }

                if (notifyTaskPushCount == 0)
                    throw new InvalidDataException($"{name}: expected duplicate NotifyTask startup pushes for current event gate tasks.");

                return tasksById;
            }

            static void AssertStartupTasksContainFreshTask(
                IReadOnlyDictionary<long, JObject> tasksById,
                long expectedTaskId,
                string name)
            {
                if (!tasksById.TryGetValue(expectedTaskId, out JObject? taskPayload))
                    throw new InvalidDataException($"{name}: missing task id {expectedTaskId}.");

                AssertEqual(1L, RequiredValue<long>(taskPayload, "State", JTokenType.Integer, $"{name} task {expectedTaskId}"), $"{name} task {expectedTaskId} State");
                JArray schedule = (JArray)RequiredToken(taskPayload, "Schedule", JTokenType.Array, $"{name} task {expectedTaskId}");
                AssertEqual(1, schedule.Count, $"{name} task {expectedTaskId} Schedule count");
                if (schedule[0] is not JObject scheduleEntry)
                    throw new InvalidDataException($"{name} task {expectedTaskId} Schedule[0]: expected JSON Object, got {schedule[0]!.Type}.");
                AssertEqual(expectedTaskId, RequiredValue<long>(scheduleEntry, "Id", JTokenType.Integer, $"{name} task {expectedTaskId} Schedule[0]"), $"{name} task {expectedTaskId} Schedule[0].Id");
                AssertEqual(0L, RequiredValue<long>(scheduleEntry, "Value", JTokenType.Integer, $"{name} task {expectedTaskId} Schedule[0]"), $"{name} task {expectedTaskId} Schedule[0].Value");
            }

            static JObject DeserializeStartupPushContentMap(Packet.Push push, string name)
            {
                try
                {
                    return JObject.Parse(MessagePackSerializer.ConvertToJson(push.Content));
                }
                catch (Exception ex) when (ex is not InvalidDataException)
                {
                    throw new InvalidDataException($"{name}: expected a MessagePack map payload.", ex);
                }
            }

            static void AssertClientItemList(
                IReadOnlyList<Item>? items,
                int validItemId,
                long validItemCount,
                int invalidItemId,
                string name)
            {
                if (items is null)
                    throw new InvalidDataException($"{name}: expected initialized item list.");
                if (items.Any(item => item.Id == invalidItemId))
                    throw new InvalidDataException($"{name}: expected invalid item id {invalidItemId} to be filtered from the startup payload.");

                List<Item> validItems = items.Where(item => item.Id == validItemId).ToList();
                AssertEqual(1, validItems.Count, $"{name} valid item {validItemId} count");
                AssertEqual(validItemCount, validItems[0].Count, $"{name} valid item {validItemId} quantity");
            }

            static void AssertStartupPayloadMapContainsKeys(
                IReadOnlyDictionary<string, Packet.Push> startupPushesByName,
                string pushName,
                string name,
                params string[] requiredKeys)
            {
                if (!startupPushesByName.TryGetValue(pushName, out Packet.Push? push))
                    throw new InvalidDataException($"{name}: expected {pushName} during login startup.");

                HashSet<string> actualKeys = new(StringComparer.Ordinal);
                try
                {
                    MessagePackReader reader = new(new System.Buffers.ReadOnlySequence<byte>(push.Content));
                    int fieldCount = reader.ReadMapHeader();
                    for (int fieldIndex = 0; fieldIndex < fieldCount; fieldIndex++)
                    {
                        string key = reader.ReadString()
                            ?? throw new InvalidDataException($"{name}: expected non-nil string map key at field {fieldIndex}.");
                        actualKeys.Add(key);
                        reader.Skip();
                    }
                }
                catch (Exception ex) when (ex is not InvalidDataException)
                {
                    throw new InvalidDataException($"{name}: expected a typed MessagePack map payload.", ex);
                }

                if (actualKeys.Count == 0)
                    throw new InvalidDataException($"{name}: expected a non-empty MessagePack map payload.");

                foreach (string requiredKey in requiredKeys)
                {
                    if (!actualKeys.Contains(requiredKey))
                        throw new InvalidDataException($"{name}: expected top-level key {requiredKey}; observed {DescribePushes(actualKeys.Order().ToArray())}.");
                }
            }

            static void AssertChatBoardLoginData(
                NotifyChatBoardLoginData payload,
                long expectedCurrentChatBoardId,
                long requiredBoardId,
                string name)
            {
                AssertEqual(expectedCurrentChatBoardId, payload.CurrentChatBoardId, $"{name} CurrentChatBoardId");
                if (payload.CurrentChatBoardId <= 0)
                    throw new InvalidDataException($"{name}: expected non-zero CurrentChatBoardId.");
                if (payload.ChatBoards.Count == 0)
                    throw new InvalidDataException($"{name}: expected non-empty ChatBoards.");
                if (!payload.ChatBoards.Any(chatBoard => chatBoard.Id == payload.CurrentChatBoardId))
                    throw new InvalidDataException($"{name}: expected ChatBoards to contain current board {payload.CurrentChatBoardId}; observed {DescribePushes(payload.ChatBoards.Select(chatBoard => chatBoard.Id.ToString()).ToArray())}.");
                if (!payload.ChatBoards.Any(chatBoard => chatBoard.Id == requiredBoardId))
                    throw new InvalidDataException($"{name}: expected ChatBoards to contain board {requiredBoardId}; observed {DescribePushes(payload.ChatBoards.Select(chatBoard => chatBoard.Id.ToString()).ToArray())}.");

                for (int chatBoardIndex = 0; chatBoardIndex < payload.ChatBoards.Count; chatBoardIndex++)
                {
                    NotifyChatBoardLoginData.NotifyChatBoardLoginDataChatBoard chatBoard = payload.ChatBoards[chatBoardIndex];
                    if (chatBoard.GetTime == 0)
                        throw new InvalidDataException($"{name}: expected ChatBoards[{chatBoardIndex}] Id {chatBoard.Id} to have non-zero GetTime.");
                    if (chatBoard.EndTime < 0)
                        throw new InvalidDataException($"{name}: expected ChatBoards[{chatBoardIndex}] Id {chatBoard.Id} EndTime to be >= 0.");
                }
            }

            static void AssertForbiddenStartupPushesAbsent(
                IReadOnlyList<string> pushNames,
                IReadOnlyList<string> forbiddenPushNames,
                string name)
            {
                foreach (string forbiddenPushName in forbiddenPushNames)
                {
                    if (pushNames.Contains(forbiddenPushName))
                        throw new InvalidDataException($"{name}: expected unsupported startup push {forbiddenPushName} not to be emitted; observed {DescribePushes(pushNames)}.");
                }
            }

            static string DescribePushes(IReadOnlyList<string> pushNames)
            {
                return pushNames.Count == 0
                    ? "<none>"
                    : string.Join(" -> ", pushNames);
            }
        }

        private static void ValidateReconnectAckClientPushNoReplayStabilityCompatibility()
        {
            using MongoCollectionOverride mongoOverride = MongoCollectionOverride.InstallForShopCompatibility();

            const long playerId = 88_005;
            const string reconnectToken = "login-account-reconnect-token";
            AscNet.Common.Database.Player player = CreateDrawCompatibilityPlayer(playerId);
            player.Token = reconnectToken;
            player.PlayerData.LastLoginTime = DateTimeOffset.UtcNow.AddDays(-2).ToUnixTimeSeconds();
            player.PlayerData.NewPlayerTaskActiveDay = 9;
            player.GatherRewards = [5, 6];
            AscNet.Common.Database.Character character = CreateDrawCompatibilityCharacter(playerId);
            character.Characters.Add(CreateLoginAccountCompatibilityCharacter(1021001, fashionId: 3021001));
            AscNet.Common.Database.Inventory inventory = CreateDrawCompatibilityInventory(
                playerId,
                [new Item { Id = AscNet.Common.Database.Inventory.Coin, Count = 12_345 }]);

            using LoopbackSessionHarness harness = new(
                character,
                player,
                inventory,
                "login-account-reconnect-ack-compat-test");
            harness.Session.stage = CreateLoginAccountCompatibilityStage(playerId);

            long lastLoginTimeBeforeReconnectAck = player.PlayerData.LastLoginTime;
            int newPlayerTaskActiveDayBeforeReconnectAck = player.PlayerData.NewPlayerTaskActiveDay;
            int[] gatherRewardsBeforeReconnectAck = player.GatherRewards.ToArray();

            const int reconnectLastMsgSeqNo = 123;
            const int reconnectPacketId = 13_008;
            InvokeRegisteredRequestHandler(
                nameof(ReconnectRequest),
                harness.Session,
                reconnectPacketId,
                new ReconnectRequest
                {
                    Token = reconnectToken,
                    PlayerId = (uint)playerId,
                    LastMsgSeqNo = reconnectLastMsgSeqNo
                });
            ReconnectResponse reconnectResponse = ReadResponsePayload<ReconnectResponse>(
                harness,
                reconnectPacketId,
                nameof(ReconnectResponse),
                "ReconnectRequest valid token response");
            AssertEqual(0, reconnectResponse.Code, "ReconnectResponse valid token Code");
            AssertEqual(reconnectToken, reconnectResponse.ReconnectToken, "ReconnectResponse valid token ReconnectToken");
            AssertEqual(reconnectLastMsgSeqNo, reconnectResponse.RequestNo, "ReconnectResponse valid token RequestNo");

            harness.SendClientPush("ReconnectAck", []);

            if (harness.TryReadAvailablePacket("ReconnectAck client push follow-up packet", out Packet followUpPacket)
                && followUpPacket.Type == Packet.ContentType.Push)
            {
                Packet.Push followUpPush = MessagePackSerializer.Deserialize<Packet.Push>(followUpPacket.Content);
                string[] forbiddenStartupReplayPushes =
                [
                    nameof(NotifyLogin),
                    nameof(NotifyPayInfo),
                    "NotifyPassportBaseInfo",
                    nameof(NotifyItemDataList),
                    nameof(NotifyStageData),
                    nameof(NotifyCharacterDataList)
                ];

                if (forbiddenStartupReplayPushes.Contains(followUpPush.Name))
                    throw new InvalidDataException($"ReconnectAck client push follow-up packet: expected no startup replay push, observed {followUpPush.Name}.");
            }

            AssertEqual(lastLoginTimeBeforeReconnectAck, player.PlayerData.LastLoginTime, "ReconnectAck client push PlayerData.LastLoginTime stability");
            AssertEqual(newPlayerTaskActiveDayBeforeReconnectAck, player.PlayerData.NewPlayerTaskActiveDay, "ReconnectAck client push PlayerData.NewPlayerTaskActiveDay stability");
            AssertIntegerList(
                gatherRewardsBeforeReconnectAck.Select(rewardId => (long)rewardId).ToArray(),
                player.GatherRewards.Select(rewardId => (long)rewardId).ToArray(),
                "ReconnectAck client push gather rewards stability");
        }

